module div_8bit(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);

    reg [7:0] dividend_reg, divisor_reg, neg_divisor;
    reg [16:0] shift_reg;
    reg [3:0] cnt;
    reg start_cnt;

    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            res_valid <= 1'b0;
            result <= 16'b0;
        end
        else begin
            if (opn_valid && ~res_valid) begin
                dividend_reg <= dividend;
                divisor_reg <= divisor;
                neg_divisor <= ~divisor_reg + 1'b1;
                shift_reg <= {dividend_reg, 9'b0};
                cnt <= 4'b0000;
                start_cnt <= 1'b1;
            end
            else begin
                if (start_cnt) begin
                    cnt <= cnt + 4'b0001;
                    shift_reg <= {neg_divisor, 9'b0, shift_reg[16:10]};
                end
                else begin
                    if (shift_reg[16]) begin
                        shift_reg <= {shift_reg[15:0], 1'b0};
                    end
                    else begin
                        shift_reg <= {shift_reg[16:0] + {1'b0, divisor_reg}, shift_reg[9:0]};
                    end
                    cnt <= cnt + 4'b0001;
                end
            end
            if (cnt[3]) begin
                if (sign && dividend_reg[7] ^ divisor_reg[7]) begin
                    result <= {1'b0, shift_reg[16:1]};
                end
                else begin
                    result <= {1'b0, shift_reg[15:0]};
                end
                res_valid <= 1'b1;
            end
            else begin
                res_valid <= 1'b0;
            end
        end
    end

endmodule
